import xml.etree.ElementTree as ET

def parse_xml_config(filename):
    tree = ET.parse(filename)
    root = tree.getroot()

    settings = {}
    for setting in root.findall('setting'):
        name = setting.attrib['name']
        value = setting.text.strip()
        settings[name] = value

    return settings